INSERT INTO campus_assistant.announcement (title, summary, content, cover_image, category, priority, is_carousel, carousel_sort, status, publisher_id, published_at) VALUES
('2026年秋季学期选课通知', '2026年秋季学期选课系统将于6月10日开放，请同学们提前查看课程安排', '<p>各位同学：</p><p>2026年秋季学期选课工作即将开始，现将有关事项通知如下：</p><h3>一、选课时间</h3><p>第一轮：6月10日 9:00 - 6月15日 17:00<br>第二轮：6月20日 9:00 - 6月25日 17:00</p><h3>二、选课方式</h3><p>登录教务系统，在"选课管理"模块进行选课操作。</p>', '86cbb16465ec48aeb720c31b1c4fd7f0_【哲风壁纸】3D-动画角色-卡通.png', 'COURSE', 2, 1, 100, 'PUBLISHED', 1, NOW()),
('期末考试安排已发布', '2025-2026学年第二学期期末考试时间表已公布', '<p>各学院：</p><p>本学期期末考试将于2026年7月1日至7月15日进行，请各位同学登录教务系统查看个人考试安排。</p><p>如有冲突请于6月20日前到教务处申请调整。</p>', '5631f4ed7efa41fb8314528a9dfe6b47_【哲风壁纸】cos-Fate.png', 'EXAM', 2, 1, 90, 'PUBLISHED', 1, NOW()),
('校园读书节活动预告', '图书馆将于6月中旬举办书香满校园主题读书节活动', '<p>为营造浓厚的校园阅读氛围，图书馆将举办2026年校园读书节活动：</p><ul><li>名家讲座：特邀知名作家分享创作心得</li><li>图书漂流：分享你读过的好书</li><li>阅读打卡：连续21天阅读挑战</li></ul><p>活动时间：6月12日-6月18日</p>', '39012dfa1b174d3384c9ce96fa8feff1_【哲风壁纸】NASA-地球-太空.png', 'ACTIVITY', 1, 1, 80, 'PUBLISHED', 1, NOW()),
('关于校园一卡通系统升级的通知', '6月5日-6月6日一卡通系统将进行维护升级', '<p>各位师生：</p><p>为提升一卡通系统服务质量，信息化中心将于2026年6月5日22:00至6月6日6:00对一卡通系统进行升级维护。</p><p>期间线上充值、消费查询等功能暂停使用，实体卡刷卡消费不受影响。</p>', 'ee7b7d838a7949c8801478ed91247f6e_【哲风壁纸】云彩-夜晚-夜景.png', 'NOTICE', 0, 1, 70, 'PUBLISHED', 1, NOW()),
('校园网络临时检修公告', '6月4日图书馆区域校园网将临时中断', '<p>因设备检修需要，图书馆区域校园网络将于6月4日14:00-16:00临时中断，请提前做好工作安排。如有不便，敬请谅解。</p>', '54a5e578a7514d4f9d5aff4357e8c332_【哲风壁纸】休闲-室内-居家.png', 'NOTICE', 0, 0, 0, 'PUBLISHED', 1, NOW());
